import React from 'react';
import { Link } from 'react-router-dom';

export default function AuthLayout({ children, title, subtitle, footerLink }) {
  return (
    <div className="login-page">
      <div className="login-panel-brand">
        <div className="brand-logo">CB</div>
        <h1>Campus Bus Services</h1>
        <p className="brand-tagline">Transportation Fee Portal</p>
        <div className="brand-footer">
          <span>Secure access for students and administrators</span>
        </div>
      </div>

      <div className="login-panel-form">
        <div className="login-card">
          <div className="login-card-header">
            <h2>{title}</h2>
            <p>{subtitle}</p>
          </div>
          {children}
          {footerLink && (
            <p className="auth-switch">
              {footerLink.text}{' '}
              <Link to={footerLink.to}>{footerLink.label}</Link>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}
